from matplotlib import pyplot as pltfrom matplotlib.patches import Rectangle'''Settings'''BOX_HEIGHT = 3.0TEXT_SIZE = 12ALPHA = 0.65COLORS = {    1: "#fdae2b",    2: "#fdae4b",    3: "#fdae6b",}'''Functions'''def _draw_detector(ax, detector):            rectangle = Rectangle(        (detector.wavelength_min, 0),        detector.width,        BOX_HEIGHT,        facecolor=COLORS[detector.number],        alpha=ALPHA    )    ax.add_patch(rectangle)            def _draw_order_label(ax, order):    detector = order.detector2        ax.text(        detector.wavelength_min + detector.width / 2,        1.90,        str(order.number),        ha="center",        va="center",        fontsize=TEXT_SIZE,    )            def _format_axes(ax, setting):    xmin, xmax = setting.wavelength_range    padding = 0.02 * (xmax - xmin)    ax.set_xlim(        xmin - padding,        xmax + padding,    )    ax.set_ylim(        0,        2,    )    ax.set_xlabel("Wavelength (μm)")    #ax.set_ylabel("Echelle order")    ax.set_yticks([])    ax.set_title(setting.name)        def plot_setting(setting, ax=None):    if ax is None:        _, ax = plt.subplots(figsize=(12, 6))    for order in setting:        _draw_order_label(ax, order)        for detector in order:            _draw_detector(ax,detector)    _format_axes(ax, setting)    return ax